// Extraction du texte principal depuis le HTML Beehiiv
const html = $input.first().json.data || $input.first().json;

let textContent = '';
if (typeof html === 'string') {
  textContent = html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 3000);
} else {
  textContent = JSON.stringify(html).substring(0, 3000);
}

if (!textContent || textContent.length < 50) {
  throw new Error('Contenu newsletter trop court ou vide. Vérifiez l\'URL Beehiiv.');
}

return [{ json: { newsletterText: textContent } }];

const response = $input.first().json;

// Compatibilité selon la version du node OpenAI
let postText = '';
if (response.message && response.message.content) {
  postText = response.message.content;
} else if (response.choices && response.choices[0]) {
  postText = response.choices[0].message.content;
} else if (typeof response === 'string') {
  postText = response;
} else {
  postText = JSON.stringify(response);
}

const now = new Date();

return [{
  json: {
    instagram_caption: postText.trim(),
    generated_at: now.toISOString(),
    source: 'newsletter',
    workflow: 'La Verticale — Newsletter to Instagram'
  }
}];

